function HackerNews() {
  const [stories, setStories] = React.useState([]);
  const [loading, setLoading] = React.useState(false);

  React.useEffect(()=>{
    setLoading(true);
    fetch('https://hacker-news.firebaseio.com/v0/topstories.json')
      .then(r=>r.json())
      .then(ids=>Promise.all(ids.slice(0,15).map(id=>fetch(`https://hacker-news.firebaseio.com/v0/item/${id}.json`).then(r=>r.json()))))
      .then(s=>{setStories(s.filter(Boolean));setLoading(false);})
      .catch(()=>setLoading(false));
  },[]);

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:12}}>
        <span style={{fontSize:18,fontWeight:700}}>Hacker News</span>
        <span style={{fontSize:12,color:'#FF6600',fontWeight:600}}>Y</span>
      </div>
      {loading && <div style={{textAlign:'center',color:'#888'}}>Loading…</div>}
      <div style={{flex:1,overflow:'auto'}}>
        {stories.map((s,i)=> (
          <a key={s.id} href={s.url||`https://news.ycombinator.com/item?id=${s.id}`} target="_blank" rel="noopener noreferrer"
            style={{display:'block',padding:'8px 0',borderBottom:'1px solid #eee',textDecoration:'none',color:'inherit'}}>
            <div style={{display:'flex',gap:8,alignItems:'baseline'}}>
              <span style={{fontSize:13,color:'#888',minWidth:20}}>{i+1}.</span>
              <span style={{fontSize:14,fontWeight:500,color:'#000'}}>{s.title}</span>
            </div>
            <div style={{fontSize:12,color:'#888',marginLeft:28,marginTop:2}}>
              {s.score} points · {s.descendants||0} comments · {s.by}
            </div>
          </a>
        ))}
      </div>
    </div>
  );
}
render(<HackerNews/>);
